use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use std::collections::HashMap;

const BILLING_INCREMENT_SECONDS: i64 = 15 * 60;
const MINIMUM_BILLING_SECONDS: i64 = 30 * 60;

pub struct InvoiceCommand;

impl InvoiceCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        let projects = aggregate_entries(&entries);

        if projects.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let mut projects: Vec<_> = projects.into_iter().collect();
        projects.sort_by(|(left_name, left_seconds), (right_name, right_seconds)| {
            right_seconds
                .cmp(left_seconds)
                .then_with(|| left_name.cmp(right_name))
        });

        let total: i64 = projects.iter().map(|(_, seconds)| seconds).sum();
        for (project, seconds) in projects {
            println!("{seconds}s  {project}");
        }
        println!("{total}s  Total");

        Ok(())
    }
}

fn aggregate_entries(entries: &[TimeEntry]) -> HashMap<String, i64> {
    let mut totals = HashMap::new();

    for entry in entries {
        if !entry.billable || entry.is_running() {
            continue;
        }

        let rounded = ((entry.duration + BILLING_INCREMENT_SECONDS - 1)
            / BILLING_INCREMENT_SECONDS)
            * BILLING_INCREMENT_SECONDS;
        let billable_seconds = rounded.max(MINIMUM_BILLING_SECONDS);
        let project = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| "No Project".to_string());
        *totals.entry(project).or_insert(0) += billable_seconds;
    }

    totals
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::api::client::MockApiClient;
    use crate::models::Project;
    use chrono::{TimeZone, Utc};

    fn entry(id: i64, duration: i64, billable: bool, project: Option<&str>) -> TimeEntry {
        TimeEntry {
            id,
            description: format!("Entry {id}"),
            start: Utc.timestamp_opt(1_700_000_000, 0).single().unwrap(),
            stop: Some(
                Utc.timestamp_opt(1_700_000_000 + duration, 0)
                    .single()
                    .unwrap(),
            ),
            duration,
            billable,
            workspace_id: 1,
            tags: vec![],
            project: project.map(|name| Project {
                id,
                name: name.to_string(),
                workspace_id: 1,
                client: None,
                is_private: false,
                active: true,
                at: Utc::now(),
                created_at: Utc::now(),
                color: "#000000".to_string(),
                billable: None,
            }),
            task: None,
            created_with: None,
        }
    }

    #[test]
    fn aggregates_rounding_floor_filtering_and_project_names() {
        let entries = vec![
            entry(1, 1, true, Some("Alpha")),
            entry(2, 1800, true, Some("Alpha")),
            entry(3, 901, true, Some("Beta")),
            entry(4, 3600, false, Some("Ignored")),
            entry(5, 3600, true, None),
        ];

        let totals = aggregate_entries(&entries);
        assert_eq!(totals.get("Alpha"), Some(&3600));
        assert_eq!(totals.get("Beta"), Some(&1800));
        assert_eq!(totals.get("No Project"), Some(&3600));
        assert!(!totals.contains_key("Ignored"));
    }

    #[test]
    fn running_entries_are_ignored() {
        let mut running = entry(1, -1, true, Some("Running"));
        running.stop = None;
        assert!(aggregate_entries(&[running]).is_empty());
    }

    #[tokio::test]
    async fn command_accepts_and_normalizes_date_filters() {
        let mut api_client = MockApiClient::new();
        let (expected_since, expected_until) = utilities::normalize_time_entry_list_filters(
            Some("2026-01-01".to_string()),
            Some("2026-01-31".to_string()),
        )
        .unwrap();
        api_client
            .expect_get_time_entries_filtered()
            .withf(move |since, until| *since == expected_since && *until == expected_until)
            .returning(|_, _| Ok(vec![]));

        InvoiceCommand::execute(
            api_client,
            Some("2026-01-01".to_string()),
            Some("2026-01-31".to_string()),
        )
        .await
        .unwrap();
    }
}

